export function initHud(){const loadTimeElement=document.getElementById("loadTime");if(!loadTimeElement)return;const displayLoadTime=()=>{let loadTime=0;const perfData=window.performance.getEntriesByType("navigation")[0];if(perfData){loadTime=perfData.domContentLoadedEventEnd||perfData.responseEnd;}else{loadTime=performance.now();}const seconds=(loadTime/1000).toFixed(2);loadTimeElement.innerText=`${seconds}s`;if(seconds<1.5){loadTimeElement.style.color="#4ade80";loadTimeElement.style.textShadow="0 0 8px rgba(74,222,128,0.6)";}else if(seconds<3.0){loadTimeElement.style.color="#facc15";loadTimeElement.style.textShadow="0 0 5px rgba(250,204,21,0.4)";}else{loadTimeElement.style.color="#ef4444";loadTimeElement.style.textShadow="0 0 5px rgba(239,68,68,0.4)";}};requestAnimationFrame(displayLoadTime);}